def solve():
    def get_prime_factors(n):
        factors = {2: 0, 3: 0, 5: 0}
        temp = n
        while temp % 2 == 0:
            factors[2] += 1
            temp //= 2
        while temp % 3 == 0:
            factors[3] += 1
            temp //= 3
        while temp % 5 == 0:
            factors[5] += 1
            temp //= 5
        return factors

    def get_cost_to_divisible(num, prime):
        if num % prime == 0:
            return 0
        return prime - (num % prime)

    # Precompute costs for numbers 1-10
    costs = {}
    for i in range(1, 11):
        costs[i] = {
            2: get_cost_to_divisible(i, 2),
            3: get_cost_to_divisible(i, 3),
            5: get_cost_to_divisible(i, 5)
        }

    t = int(input())
    for _ in range(t):
        n, k = map(int, input().split())
        a = list(map(int, input().split()))

        # Get required prime factors for k
        required = get_prime_factors(k)

        # Count current prime factors in product
        current = {2: 0, 3: 0, 5: 0}
        for num in a:
            factors = get_prime_factors(num)
            for prime in [2, 3, 5]:
                current[prime] += factors[prime]

        # Calculate missing factors
        missing = {}
        for prime in [2, 3, 5]:
            missing[prime] = max(0, required[prime] - current[prime])

        # If no missing factors, answer is 0
        if all(missing[p] == 0 for p in [2, 3, 5]):
            print(0)
            continue

        # For each prime, sort elements by cost to add that prime
        prime_elements = {}
        for prime in [2, 3, 5]:
