                for i in range(n):
                    cost_list.append((costs[a[i]][prime], i))
                cost_list.sort()
                prime_elements[prime] = cost_list

        # Handle different cases
        if k == 2:
            # Need one factor of 2
            min_cost = min(costs[a[i]][2] for i in range(n))
            print(min_cost)
        elif k == 3:
            # Need one factor of 3
            min_cost = min(costs[a[i]][3] for i in range(n))
            print(min_cost)
        elif k == 5:
            # Need one factor of 5
            min_cost = min(costs[a[i]][5] for i in range(n))
            print(min_cost)
        elif k == 4:
            # Need two factors of 2
            # Either one element contributes 2 factors, or two elements each contribute 1
            cost_list_2 = [(costs[a[i]][2], i) for i in range(n)]
            cost_list_2.sort()

            # Option 1: One element gives 2 factors of 2
            # This means making an element divisible by 4
            min_cost_single = float('inf')
            for i in range(n):
                num = a[i]
