def solve():
    n = int(input())
    a = list(map(int, input().split()))

    # Count frequencies
    freq = {}
    for val in a:
        freq[val] = freq.get(val, 0) + 1

    result = 0

    # Count pairs with same values
    for count in freq.values():
        if count > 1:
            result += count * (count - 1) // 2

    # Count pairs between 1 and 2
    count1 = freq.get(1, 0)
    count2 = freq.get(2, 0)
    result += count1 * count2

    return result

