class Solution:
    def matrixSum(self, nums: List[List[int]]) -> int:
        # Step 1: Sort each row in descending order
        for row in nums:
            row.sort(reverse=True)

        # Step 2: Initialize score
        score = 0

        # Step 3: Determine the number of iterations (max length of any row)
        max_cols = max(len(row) for row in nums)

        # Step 4: Iterate through each column index
        for col in range(max_cols):
            # Collect the element at current column index from each row (if exists)
            current_elements = []
            for row in nums:
                if col < len(row):
                    current_elements.append(row[col])

            # Find the maximum among collected elements and add to score
            if current_elements:
                score += max(current_elements)

        return score

class Solution:
    def maxStrength(self, nums: List[int]) -> int:
        if len(nums) == 1:
            return nums[0]

        positives = [x for x in nums if x > 0]
        negatives = [x for x in nums if x < 0]
        zero_count = nums.count(0)

        # If all elements are zero
        if len(positives) == 0 and len(negatives) == 0:
            return 0

        # Compute product of all positive numbers
        pos_product = 1
        for x in positives:
            pos_product *= x

        # Compute product of all negative numbers
        neg_product = 1
        for x in negatives:
            neg_product *= x

        # If there's an even number of negatives, their product is positive
        if len(negatives) % 2 == 0:
            if len(negatives) == 0:
                # Only positives and possibly zeros
                return pos_product
            else:
                # Even number of negatives: include all
                return pos_product * neg_product
        else:
            # Odd number of negatives: exclude the one closest to zero (i.e., the maximum negative)
            if len(negatives) == 1:
                # Only one negative number
                if len(positives) > 0:
                    # There are positives, so just use them
                    return pos_product
                else:
                    # No positives, one negative, might have zeros
                    if zero_count > 0:
                        return 0
                    else:
                        # Must take the single negative
                        return negatives[0]
            else:
                # More than one negative; remove the maximum (closest to zero)
                max_neg = max(negatives)
                neg_product //= max_neg  # Integer division because we know max_neg is a factor
                return pos_product * neg_product

class Solution:
    def buyChoco(self, prices: List[int], money: int) -> int:
        # Initialize first and second minimum prices
        first_min = float('inf')
        second_min = float('inf')

        # Find the two smallest prices in one pass
        for price in prices:
            if price < first_min:
                # New smallest found, previous smallest becomes second smallest
                second_min = first_min
                first_min = price
            elif price < second_min:
                # New second smallest found
                second_min = price

        # Calculate the minimum cost for two chocolates
        min_cost = first_min + second_min

        # Check if we can afford the two cheapest chocolates
        if min_cost <= money:
            return money - min_cost
        else:
            # Cannot afford without going into debt
            return money

class Solution:
    def colorTheArray(self, n: int, queries: List[List[int]]) -> List[int]:
        # Initialize the nums array with all zeros (uncolored)
        nums = [0] * n
        # Initialize the count of adjacent pairs with same color
        current_count = 0
        # Result array to store the count after each query
        result = []

        for index, color in queries:
            # Check the pairs before updating the color at index
            # Left pair (index-1, index)
            if index > 0:
                if nums[index - 1] == nums[index] and nums[index] != 0:
                    current_count -= 1

            # Right pair (index, index+1)
            if index < n - 1:
                if nums[index] == nums[index + 1] and nums[index] != 0:
                    current_count -= 1

            # Update the color at the given index
            nums[index] = color

            # Check the pairs after updating the color at index
            # Left pair (index-1, index)
            if index > 0:
                if nums[index - 1] == nums[index] and nums[index] != 0:
                    current_count += 1

            # Right pair (index, index+1)
            if index < n - 1:
                if nums[index] == nums[index + 1] and nums[index] != 0:
                    current_count += 1

            # Append the current count to the result
            result.append(current_count)

        return result

class Solution:
    def doesValidArrayExist(self, derived: List[int]) -> bool:
        # Compute the cumulative XOR of all elements in the derived array
        xor_result = 0
        for value in derived:
            xor_result ^= value

        # A valid original array exists if and only if the total XOR is 0
        return xor_result == 0

class Solution:
    def minLength(self, s: str) -> int:
        stack = []

        for char in s:
            # Check if we can form "AB" or "CD" with the current character and the top of the stack
            if stack and ((stack[-1] == 'A' and char == 'B') or (stack[-1] == 'C' and char == 'D')):
                # Remove the matching character from the stack
                stack.pop()
            else:
                # Otherwise, push the current character onto the stack
                stack.append(char)

        # The length of the stack is the minimum possible length of the string
        return len(stack)

class Solution:
    def punishmentNumber(self, n: int) -> int:
        def canPartition(s, target, start, current_sum):
            # Base case: if we've processed the entire string
            if start == len(s):
                return current_sum == target

            # Try all possible partitions starting from 'start'
            for end in range(start + 1, len(s) + 1):
                # Extract substring and convert to integer
                substring = s[start:end]
                num = int(substring)

                # If adding this number doesn't exceed target, continue recursively
                if current_sum + num <= target:
                    if canPartition(s, target, end, current_sum + num):
                        return True

            return False

        result = 0
        for i in range(1, n + 1):
            square = i * i
            square_str = str(square)

            # Check if the square string can be partitioned to sum to i
            if canPartition(square_str, i, 0, 0):
                result += square

        return result

class Solution:
    def minimumSum(self, n: int, k: int) -> int:
        # Set to store the selected numbers
        selected = set()
        # Set to store the forbidden numbers (complements that would sum to k)
        forbidden = set()

        current = 1
        while len(selected) < n:
            # If current number is not forbidden, we can select it
            if current not in forbidden:
                selected.add(current)
                # Mark its complement as forbidden if it's a positive number and different from current
                if k - current > 0 and k - current != current:
                    forbidden.add(k - current)
            current += 1

        return sum(selected)

class Solution:
    def theMaximumAchievableX(self, num: int, t: int) -> int:
        # The maximum achievable x is num + 2*t
        # This is because in each operation, we can reduce the distance between x and num by 2
        # So with t operations, we can handle a maximum initial distance of 2*t
        return num + 2 * t

class Solution:
    def minimumCost(self, s: str) -> int:
        n = len(s)
        total_cost = 0

        # Iterate through the string to find transitions
        for i in range(n - 1):
            if s[i] != s[i + 1]:
                # Calculate the cost to fix this transition
                cost = min(i + 1, n - (i + 1))
                total_cost += cost

        return total_cost

class Solution:
    def removeTrailingZeros(self, num: str) -> str:
        # Start from the end of the string
        i = len(num) - 1

        # Move backwards until we find a non-zero digit
        while i >= 0 and num[i] == '0':
            i -= 1

        # Return the substring from start to the last non-zero digit (inclusive)
        return num[:i+1]

