class Solution:
    def canTraverseAllPairs(self, nums: List[int]) -> bool:
        n = len(nums)
        if n == 1:
            return True

        # Check for presence of 1
        if 1 in nums:
            return False

        # Sieve of Eratosthenes to compute SPF
        def sieve_of_eratosthenes(max_val):
            spf = list(range(max_val + 1))
            for i in range(2, int(max_val**0.5) + 1):
                if spf[i] == i:  # i is a prime
                    for j in range(i * i, max_val + 1, i):
                        if spf[j] == j:
                            spf[j] = i
            return spf

        max_val = max(nums)
        spf = sieve_of_eratosthenes(max_val)

        # Function to get prime factors using SPF
        def get_prime_factors(num):
            factors = set()
            while num > 1:
                factors.add(spf[num])
                num //= spf[num]
            return factors

        # Union-Find class
        class UnionFind:
            def __init__(self, size):
                self.parent = list(range(size))
                self.rank = [0] * size
                self.components = size

            def find(self, x):
                if self.parent[x] != x:
                    self.parent[x] = self.find(self.parent[x])
                return self.parent[x]

            def union(self, x, y):
                px, py = self.find(x), self.find(y)
                if px == py:
                    return
                if self.rank[px] < self.rank[py]:
                    px, py = py, px
                self.parent[py] = px
                if self.rank[px] == self.rank[py]:
                    self.rank[px] += 1
                self.components -= 1

        # Map each prime to the indices having it
        from collections import defaultdict
        prime_to_indices = defaultdict(list)
        for idx, num in enumerate(nums):
            prime_factors = get_prime_factors(num)
            for p in prime_factors:
                prime_to_indices[p].append(idx)

        # Initialize Union-Find and perform unions
        uf = UnionFind(n)
        for indices_list in prime_to_indices.values():
            for i in range(1, len(indices_list)):
                uf.union(indices_list[0], indices_list[i])

        # If all indices are in one component, return True
        return uf.components == 1

class Solution:
    def smallestString(self, s: str) -> str:
        # Convert string to list for easier manipulation
        s_list = list(s)
        n = len(s_list)

        # Find the first non-'a' character
        start = 0
        while start < n and s_list[start] == 'a':
            start += 1

        # If all characters are 'a', we must transform exactly once
        # Transform the last 'a' to 'z'
        if start == n:
            s_list[-1] = 'z'
            return ''.join(s_list)

        # Transform consecutive non-'a' characters starting from 'start'
        # until we hit an 'a' or reach the end of the string
        for i in range(start, n):
            if s_list[i] == 'a':
                break
            # Decrement the character
            s_list[i] = chr(ord(s_list[i]) - 1)

        return ''.join(s_list)

class Solution:
    def countBeautifulPairs(self, nums: List[int]) -> int:
        def gcd(a, b):
            while b:
                a, b = b, a % b
            return a

        def first_digit(n):
            while n >= 10:
                n //= 10
            return n

        def last_digit(n):
            return n % 10

        count = 0
        n = len(nums)

        for i in range(n):
            for j in range(i + 1, n):
                first = first_digit(nums[i])
                last = last_digit(nums[j])
                if gcd(first, last) == 1:
                    count += 1

        return count

class Solution:
    def longestEqualSubarray(self, nums: List[int], k: int) -> int:
        # Create a dictionary to store the positions of each unique value
        pos_map = {}
        for i, num in enumerate(nums):
            if num not in pos_map:
                pos_map[num] = []
            pos_map[num].append(i)

        max_len = 0

        # For each unique value, apply sliding window on its positions
        for positions in pos_map.values():
            left = 0
            # Iterate through the positions with right pointer
            for right in range(len(positions)):
                # Calculate the number of deletions needed for current window
                # Deletions = (actual span) - (count of target elements)
                while (positions[right] - positions[left] + 1) - (right - left + 1) > k:
                    left += 1

                # Update the maximum length of equal subarray
                max_len = max(max_len, right - left + 1)

        return max_len

class Solution:
    def relocateMarbles(self, nums: List[int], moveFrom: List[int], moveTo: List[int]) -> List[int]:
        # Step 1: Initialize occupied positions using a set
        occupied = set(nums)

        # Step 2: Process each move operation
        for i in range(len(moveFrom)):
            # Remove source position (it becomes unoccupied)
            occupied.remove(moveFrom[i])
            # Add destination position (it becomes occupied)
            occupied.add(moveTo[i])

        # Step 3: Convert to sorted list and return
        return sorted(list(occupied))

class Solution:
    def sumOfSquares(self, nums: List[int]) -> int:
        n = len(nums)
        total = 0

        # Check each 1-indexed position from 1 to n
        for i in range(1, n + 1):
            # If i divides n evenly, then it's a special element
            if n % i == 0:
                # Convert to 0-indexed and add the square to our total
                total += nums[i - 1] * nums[i - 1]

        return total

class Solution:
    def maximumNumberOfStringPairs(self, words: List[str]) -> int:
        n = len(words)
        pairs = 0

        # For each string, check if its reverse exists at a later position
        for i in range(n - 1):
            reversed_word = words[i][::-1]
            # Look for the reversed string in remaining positions
            for j in range(i + 1, n):
                if words[j] == reversed_word:
                    pairs += 1
                    break  # Found a match, no need to check further as all strings are distinct

        return pairs

class Solution:
    def specialPerm(self, nums: List[int]) -> int:
        MOD = 10**9 + 7
        n = len(nums)

        # Precompute compatibility matrix
        compatible = [[False] * n for _ in range(n)]
        for i in range(n):
            for j in range(n):
                if i != j and (nums[i] % nums[j] == 0 or nums[j] % nums[i] == 0):
                    compatible[i][j] = True

        # DP table: dp[mask][last] = number of ways to arrange elements in mask ending with 'last'
        dp = [[0] * n for _ in range(1 << n)]

        # Initialize: single element sequences
        for i in range(n):
            dp[1 << i][i] = 1

        # Fill DP table
        for mask in range(1 << n):
            for last in range(n):
                if not (mask & (1 << last)):  # if 'last' is not in the mask, skip
                    continue
                if dp[mask][last] == 0:  # no ways to reach this state
                    continue

                # Try to extend with each unused element
                for next_elem in range(n):
                    if mask & (1 << next_elem):  # if 'next_elem' is already used, skip
                        continue
                    if compatible[last][next_elem]:
                        new_mask = mask | (1 << next_elem)
                        dp[new_mask][next_elem] = (dp[new_mask][next_elem] + dp[mask][last]) % MOD

        # Sum all permutations that use all elements
        full_mask = (1 << n) - 1
        result = 0
        for i in range(n):
            result = (result + dp[full_mask][i]) % MOD

        return result

class Solution:
    def minimizeConcatenatedLength(self, words: List[str]) -> int:
        n = len(words)
        # dp[i][first_char][last_char] = minimum length of string using first i+1 words
        # We only need the previous state, so we can optimize space by using two arrays
        import sys

        # Initialize for the first word
        first_word = words[0]
        first_char = ord(first_word[0]) - ord('a')
        last_char = ord(first_word[-1]) - ord('a')

        # prev[first][last] = min length with this first and last char
        prev = {}
        prev[(first_char, last_char)] = len(first_word)

        # Process each word from index 1 to n-1
        for i in range(1, n):
            word = words[i]
            w_first = ord(word[0]) - ord('a')
            w_last = ord(word[-1]) - ord('a')
            w_len = len(word)

            curr = {}
            for (p_first, p_last), p_len in prev.items():
                # Option 1: append current word to previous string: prev_str + word
                # Check if p_last == w_first for overlap
                if p_last == w_first:
                    new_len = p_len + w_len - 1
                else:
                    new_len = p_len + w_len

                new_key = (p_first, w_last)
                if new_key not in curr or curr[new_key] > new_len:
                    curr[new_key] = new_len

                # Option 2: prepend current word to previous string: word + prev_str
                # Check if w_last == p_first for overlap
                if w_last == p_first:
                    new_len = w_len + p_len - 1
                else:
                    new_len = w_len + p_len

                new_key = (w_first, p_last)
                if new_key not in curr or curr[new_key] > new_len:
                    curr[new_key] = new_len

            prev = curr

        # Find the minimum among all possible final states
        return min(prev.values())

class Solution:
    def maximumJumps(self, nums: List[int], target: int) -> int:
        n = len(nums)
        # Initialize dp array with negative infinity
        dp = [-float('inf')] * n
        # Base case: we start at index 0 with 0 jumps
        dp[0] = 0

        # Fill the dp array using bottom-up approach
        for i in range(1, n):
            for j in range(i):
                # Check if jump from j to i is valid
                if -target <= nums[i] - nums[j] <= target:
                    # If j is reachable, update dp[i]
                    if dp[j] != -float('inf'):
                        dp[i] = max(dp[i], dp[j] + 1)

        # Return the result
        return dp[n-1] if dp[n-1] != -float('inf') else -1

class Solution:
    def numberOfGoodSubarraySplits(self, nums: List[int]) -> int:
        MOD = 10**9 + 7

        # Step 1: Find all positions of 1s
        ones_positions = []
        for i, num in enumerate(nums):
            if num == 1:
                ones_positions.append(i)

        # Step 2: Handle edge cases
        if len(ones_positions) == 0:
            return 0
        if len(ones_positions) == 1:
            return 1

        # Step 3: Calculate the number of ways
        result = 1
        for i in range(1, len(ones_positions)):
            # Number of zeros between consecutive 1s + 1 for split positions
            diff = ones_positions[i] - ones_positions[i-1]
            result = (result * diff) % MOD

        return result

class Solution:
    def findPrimePairs(self, n: int) -> List[List[int]]:
        # Edge case: if n is less than 4, no valid prime pairs can exist
        if n < 4:
            return []

        # Sieve of Eratosthenes to find all primes up to n
        is_prime = [True] * (n + 1)
        is_prime[0] = is_prime[1] = False  # 0 and 1 are not primes

        for i in range(2, int(n**0.5) + 1):
            if is_prime[i]:
                for j in range(i * i, n + 1, i):
                    is_prime[j] = False

        result = []
        # Only iterate up to n//2 to ensure x <= y and avoid duplicate pairs
        for x in range(2, n // 2 + 1):
            if is_prime[x]:
                y = n - x
                if is_prime[y]:
                    result.append([x, y])

        return result

