class Solution:
    def minimumChanges(self, s: str, k: int) -> int:
        n = len(s)

        # Function to calculate the minimum changes to make s[l:r+1] a semi-palindrome
        def getMinChanges(l, r):
            length = r - l + 1
            if length == 1:
                return float('inf')  # By definition, single character is not a semi-palindrome

            min_changes = float('inf')

            # Try all valid divisors d
            for d in range(1, length):
                if length % d != 0:
                    continue

                changes = 0
                # For each group defined by modulo d
                for start in range(d):
                    # Collect characters in this group
                    group = []
                    for i in range(l + start, r + 1, d):
                        group.append(s[i])

                    # Count mismatches to make this group a palindrome
                    m = len(group)
                    for i in range(m // 2):
                        if group[i] != group[m - 1 - i]:
                            changes += 1

                min_changes = min(min_changes, changes)

            return min_changes if min_changes != float('inf') else 0

        # Precompute cost for all substrings
        cost = [[0] * n for _ in range(n)]
        for i in range(n):
            for j in range(i, n):
                cost[i][j] = getMinChanges(i, j)

        # DP table: dp[i][j] = min changes to partition first i chars into j substrings
        dp = [[float('inf')] * (k + 1) for _ in range(n + 1)]
        dp[0][0] = 0

        for i in range(1, n + 1):
            for j in range(1, min(i, k) + 1):
                # Try all possible starting points of the last substring
                for prev in range(j - 1, i):
                    dp[i][j] = min(dp[i][j], dp[prev][j - 1] + cost[prev][i - 1])

        return dp[n][k]

class Solution:
    def splitWordsBySeparator(self, words: List[str], separator: str) -> List[str]:
        result = []

        for word in words:
            # Split the word by the separator
            parts = word.split(separator)

            # Add non-empty parts to the result
            for part in parts:
                if part:  # Check if the part is not an empty string
                    result.append(part)

        return result

class TrieNode:
    def __init__(self):
        self.children = {}
        self.is_end = False

class Solution:
    def longestValidSubstring(self, word: str, forbidden: List[str]) -> int:
        # Step 1: Build Trie with reversed forbidden words
        root = TrieNode()
        for f_word in forbidden:
            node = root
            # Insert reversed word into trie
            for char in reversed(f_word):
                if char not in node.children:
                    node.children[char] = TrieNode()
                node = node.children[char]
            node.is_end = True

        n = len(word)
        left = 0
        max_len = 0
        # last_invalid_index tracks the rightmost start of any forbidden substring
        last_invalid_index = -1

        for right in range(n):
            # Check backwards up to 10 characters (max forbidden length)
            node = root
            # We check from right backwards, at most 10 steps or until left
            for k in range(right, max(left-1, right - 10), -1):
                char = word[k]
                if char not in node.children:
                    break
                node = node.children[char]
                if node.is_end:
                    # Found a forbidden substring from k to right
                    last_invalid_index = max(last_invalid_index, k)

            # Move left pointer to ensure no forbidden substring is included
            left = max(left, last_invalid_index + 1)

            # Update maximum length
            max_len = max(max_len, right - left + 1)

        return max_len

class Solution:
    def finalString(self, s: str) -> str:
        result = ""
        for char in s:
            if char == 'i':
