        return result

class Solution:
    def sortVowels(self, s: str) -> str:
        # Define vowels set for quick lookup
        vowels_set = set('aeiouAEIOU')

        # Extract all vowels from the string
        vowels = []
        for char in s:
            if char in vowels_set:
                vowels.append(char)

        # Sort vowels by their ASCII values
        vowels.sort()

        # Reconstruct the string
        result = []
        vowel_index = 0

        for char in s:
            if char in vowels_set:
                # Place the next sorted vowel
                result.append(vowels[vowel_index])
                vowel_index += 1
            else:
                # Keep consonants in their original places
                result.append(char)

        return ''.join(result)

class Solution:
    def isGood(self, nums: List[int]) -> bool:
        # Step 1: Find the maximum element -> this is our candidate for n
        n = max(nums)

        # Step 2: Check if the length matches base[n]'s length, which is n + 1
        if len(nums) != n + 1:
            return False

        # Step 3: Count the frequency of each number
        freq = {}
        for num in nums:
            freq[num] = freq.get(num, 0) + 1

        # Step 4: Validate frequencies
        # All numbers from 1 to n-1 must appear exactly once
        for i in range(1, n):
            if freq.get(i, 0) != 1:
                return False

        # The number n must appear exactly twice
        if freq.get(n, 0) != 2:
            return False

        # If all conditions pass
        return True

class Solution:
    def maxSum(self, nums: List[int]) -> int:
        # Helper function to find maximum digit in a number
        def max_digit(n):
            return max(int(digit) for digit in str(n))

        # Group numbers by their maximum digit
        groups = {}
        for num in nums:
            max_d = max_digit(num)
            if max_d not in groups:
                groups[max_d] = []
            groups[max_d].append(num)

        max_sum = -1

        # For each group, if it has at least 2 numbers,
        # find the two largest and update max_sum
        for group in groups.values():
            if len(group) >= 2:
                group.sort(reverse=True)
                current_sum = group[0] + group[1]
                max_sum = max(max_sum, current_sum)

        return max_sum

class Solution:
    def canSplitArray(self, nums: List[int], m: int) -> bool:
        # Base case: if the array has 1 or 2 elements, it's always possible to split
        if len(nums) <= 2:
            return True

        # Check if there exists at least one adjacent pair with sum >= m
        for i in range(len(nums) - 1):
            if nums[i] + nums[i + 1] >= m:
                return True

        # If no such pair exists, it's not possible to split the array
        return False

class Solution:
    def countPairs(self, nums: List[int], target: int) -> int:
        count = 0
        n = len(nums)

        # Check all possible pairs (i, j) where i < j
        for i in range(n):
            for j in range(i + 1, n):
                if nums[i] + nums[j] < target:
                    count += 1

        return count

import math
from typing import List

class Solution:
    def minimumSeconds(self, nums: List[int]) -> int:
        positions = {}
        n = len(nums)
        for i, val in enumerate(nums):
            if val not in positions:
                positions[val] = []
            positions[val].append(i)

        min_time = float('inf')

        for val, pos_list in positions.items():
            max_gap_time = 0
            m = len(pos_list)

            # Regular gaps between successive positions
            for i in range(m):
                curr = pos_list[i]
                next_i = pos_list[(i + 1) % m]

                if next_i > curr:
                    gap = next_i - curr - 1
                else:  # Wraps around
                    gap = (next_i + n) - curr - 1

                time_needed = math.ceil(gap / 2)
                max_gap_time = max(max_gap_time, time_needed)

            min_time = min(min_time, max_gap_time)

        return int(min_time)

class Solution:
    def countSteppingNumbers(self, low: str, high: str) -> int:
        MOD = 10**9 + 7

        def minus_one(s):
            # Convert string to list for easier manipulation
            s_list = list(s)
            i = len(s_list) - 1
            # Handle borrowing
            while i >= 0 and s_list[i] == '0':
                s_list[i] = '9'
                i -= 1
            if i >= 0:
                s_list[i] = str(int(s_list[i]) - 1)
            # Remove leading zeros, but keep at least one digit
            result = ''.join(s_list).lstrip('0')
            return result if result else '0'

        def count(num_str):
            n = len(num_str)
            memo = {}

            def dp(pos, prev_digit, tight, started):
                if pos == n:
                    return 1 if started else 0

                if (pos, prev_digit, tight, started) in memo:
                    return memo[(pos, prev_digit, tight, started)]

                limit = int(num_str[pos]) if tight else 9
                res = 0

                if not started:
                    # We can place 0 (continue leading zeros)
                    res = dp(pos + 1, -1, False, False)
                    # Or start placing digits from 1 to limit
                    for d in range(1, limit + 1):
                        res = (res + dp(pos + 1, d, tight and (d == limit), True)) % MOD
                else:
                    # We must place a digit adjacent to prev_digit
                    candidates = []
                    if prev_digit > 0:
                        candidates.append(prev_digit - 1)
                    if prev_digit < 9:
                        candidates.append(prev_digit + 1)

                    for d in candidates:
                        if d <= limit:
                            res = (res + dp(pos + 1, d, tight and (d == limit), True)) % MOD

                memo[(pos, prev_digit, tight, started)] = res
                return res

            return dp(0, -1, True, False)

        low_prev = minus_one(low)
        count_high = count(high)
        count_low_prev = count(low_prev)
        return (count_high - count_low_prev) % MOD

class Solution:
    def accountBalanceAfterPurchase(self, purchaseAmount: int) -> int:
        # Round to the nearest multiple of 10, with ties going to the higher multiple
        roundedAmount = round(purchaseAmount / 10) * 10
        # Special case for when purchaseAmount is exactly halfway (ends in 5)
        # Python's round() rounds to the nearest even number, so we need to adjust
        if purchaseAmount % 10 == 5:
            roundedAmount = ((purchaseAmount // 10) + 1) * 10

        return 100 - roundedAmount

class Solution:
    def isAcronym(self, words: List[str], s: str) -> bool:
        # Step 1: Check if lengths match
        if len(s) != len(words):
            return False

        # Step 2: Compare each character
        for i in range(len(words)):
            # Get the first character of the current word
            first_char = words[i][0]

            # Compare with the corresponding character in s
            if first_char != s[i]:
                return False

        # Step 3: If all characters matched, return True
        return True

class Solution:
    def canMakeSubsequence(self, str1: str, str2: str) -> bool:
        # Initialize two pointers for both strings
        ptr1, ptr2 = 0, 0

        # Helper function to get next character cyclically
        def next_char(c):
            return chr(((ord(c) - ord('a') + 1) % 26) + ord('a'))

        # Traverse both strings
        while ptr1 < len(str1) and ptr2 < len(str2):
            # Current characters
            c1 = str1[ptr1]
            c2 = str2[ptr2]

            # Check if they match directly or after one increment
            if c1 == c2 or next_char(c1) == c2:
                # Move pointer for str2 since we found a match
                ptr2 += 1

            # Always move pointer for str1
            ptr1 += 1

        # If we've matched all characters in str2, return True
        return ptr2 == len(str2)

class Solution:
    def numberOfPoints(self, nums: List[List[int]]) -> int:
        # Create a set to store all unique integer points covered by cars
        covered_points = set()

        # Iterate through each car's coverage range
        for start, end in nums:
            # Add all integer points in the range [start, end] to the set
            for point in range(start, end + 1):
                covered_points.add(point)

        # Return the number of unique covered points
        return len(covered_points)

class Solution:
    def minOperations(self, nums: List[int], k: int) -> int:
        # Set to keep track of collected elements from 1 to k
        collected = set()
        operations = 0

        # Traverse the array from the end
        for i in range(len(nums) - 1, -1, -1):
            operations += 1
            # If the current element is in the target range and not yet collected
            if 1 <= nums[i] <= k and nums[i] not in collected:
                collected.add(nums[i])
                # If we have collected all elements from 1 to k, return the operation count
                if len(collected) == k:
                    return operations

        # This line is theoretically unreachable due to problem constraints
        return operations

class Solution:
    def minimumRightShifts(self, nums: List[int]) -> int:
        n = len(nums)

        # Edge case: single element is always sorted
        if n == 1:
            return 0

        # Check if already sorted
        if all(nums[i] <= nums[i+1] for i in range(n-1)):
            return 0

        # Count break points where nums[i] > nums[i+1]
        breaks = 0
        break_index = -1

        for i in range(n):
            if nums[i] > nums[(i + 1) % n]:
                breaks += 1
                break_index = i

        # If more than one break, impossible to sort
        if breaks != 1:
            return -1

        # Calculate right shifts needed
        # If break is at index i, we need (n-1-i) right shifts
        return n - 1 - break_index

class Solution:
    def maximumSum(self, nums: List[int]) -> int:
        from collections import defaultdict
        import math

        # Helper function to compute the square-free part of a number
        def square_free_part(x):
            result = 1
            i = 2
            while i * i <= x:
                count = 0
                while x % i == 0:
                    x //= i
                    count += 1
                # Only include the prime factor if it has an odd power
                if count % 2 == 1:
                    result *= i
                i += 1
            # If x is still greater than 1, then it's a prime factor with power 1
            if x > 1:
                result *= x
            return result

        # Dictionary to store the sum of numbers grouped by their square-free part
        group_sums = defaultdict(int)

        # Iterate over the indices (1-based) and their corresponding values
        for i in range(1, len(nums) + 1):
            sqf = square_free_part(i)
            group_sums[sqf] += nums[i - 1]

        # Return the maximum sum among all groups
        return max(group_sums.values())

class Solution:
    def maxSubarrays(self, nums: List[int]) -> int:
        # Step 1: Calculate the minimum possible sum (AND of entire array)
        min_sum = nums[0]
        for num in nums[1:]:
            min_sum &= num

        # If the minimum sum is greater than 0, we can't do better than one subarray
        if min_sum > 0:
            return 1

        # Step 2: Greedily split into subarrays with score 0
        count = 0
        current_and = (1 << 20) - 1  # All ones mask (larger than max possible num)

        for num in nums:
            current_and &= num
            if current_and == 0:
                count += 1
                current_and = (1 << 20) - 1  # Reset for next subarray

        return count

class Solution:
    def minLengthAfterRemovals(self, nums: List[int]) -> int:
        # Step 1: Count frequency of each element
        freq_map = {}
        for num in nums:
            freq_map[num] = freq_map.get(num, 0) + 1

        # Step 2: Find the maximum frequency
        max_freq = max(freq_map.values())

        # Step 3: Calculate the number of remaining elements
        rest = len(nums) - max_freq

        # Step 4: Apply the logic
        # If max_freq > rest, some elements from the largest group will remain
        # Otherwise, we can pair all or all but one depending on total length parity
        if max_freq > rest:
            return max_freq - rest
        else:
            return len(nums) % 2

class Solution:
    def sumIndicesWithKSetBits(self, nums: List[int], k: int) -> int:
        def count_set_bits(n):
            """Count the number of 1's in the binary representation of n"""
            count = 0
            while n:
                count += n & 1  # Check if the last bit is 1
                n >>= 1         # Right shift to check the next bit
            return count

        total_sum = 0
        for i in range(len(nums)):
            if count_set_bits(i) == k:
                total_sum += nums[i]

        return total_sum

class Solution:
    def shortestBeautifulSubstring(self, s: str, k: int) -> str:
        # Phase 1: Validation
        if s.count('1') < k:
            return ""

        min_length = len(s) + 1  # Initialize to a large value
        beautiful_substrings = []

        # Phase 2: Finding Candidate Substrings
        for i in range(len(s)):
            if s[i] == '0':
                continue  # A beautiful substring must start with '1'

            count_ones = 0
            for j in range(i, len(s)):
                if s[j] == '1':
                    count_ones += 1

                if count_ones == k:
                    # Found a beautiful substring from index i to j
                    substring = s[i:j+1]
                    length = j - i + 1

                    if length < min_length:
                        min_length = length
                        beautiful_substrings = [substring]  # Start a new list
                    elif length == min_length:
                        beautiful_substrings.append(substring)

                    break  # No need to extend further from this start point

        # If no beautiful substring found (should not happen given the check)
        if not beautiful_substrings:
            return ""

        # Phase 4: Selecting Lexicographically Smallest
        # Sort the list of beautiful substrings of minimum length
        beautiful_substrings.sort()

        # The first element after sorting is the lexicographically smallest
        return beautiful_substrings[0]

class Solution:
    def maxSum(self, nums: List[int], k: int) -> int:
        MOD = 10**9 + 7
        # Step 1: Count the number of set bits at each position (0 to 30)
        bit_count = [0] * 32
        for num in nums:
            for i in range(32):
                if num & (1 << i):
                    bit_count[i] += 1

        # Step 2: Construct the k largest numbers greedily
        selected = [0] * k
        for i in range(31, -1, -1):  # Start from the most significant bit
            cnt = bit_count[i]
            for j in range(min(cnt, k)):
                selected[j] |= (1 << i)

        # Step 3: Calculate the sum of squares modulo 10^9 + 7
        result = 0
        for num in selected:
            result = (result + (num * num) % MOD) % MOD

        return result

class Solution:
    def maximumTripletValue(self, nums: List[int]) -> int:
        max_value = 0
        n = len(nums)

        # Enumerate all valid triplets (i, j, k) where i < j < k
        for i in range(n - 2):
            for j in range(i + 1, n - 1):
                for k in range(j + 1, n):
                    # Calculate the triplet value
                    value = (nums[i] - nums[j]) * nums[k]
                    # Update maximum if current value is greater
                    if value > max_value:
                        max_value = value

        return max_value

class Solution:
    def minGroupsForValidAssignment(self, nums: List[int]) -> int:
        # Step 1: Count frequency of each value
        from collections import Counter
        freq = list(Counter(nums).values())

        # Helper function to check if a frequency can be decomposed into groups of size k and k-1
        def can_decompose(f, k):
            if k == 1:
                return f  # Need f groups of size 1
            remainder = f % k
            if remainder == 0:
                return f // k
            elif remainder == k - 1:
                return f // k + 1
            else:
                need_extra = (k - 1) - remainder
                if f // k >= need_extra:
                    return f // k + 1  # Convert 'need_extra' k-groups to (k-1)-groups and form one new (k-1) group
                else:
                    return -1  # Impossible

        # Step 2: Try different values of k from largest to smallest
        max_freq = max(freq)
        for k in range(max_freq, 0, -1):
            total_groups = 0
            valid = True

            # Step 3: Check if all frequencies can be decomposed with this k
            for f in freq:
                groups_needed = can_decompose(f, k)
                if groups_needed == -1:
                    valid = False
                    break
                total_groups += groups_needed

            # If all frequencies are valid, return the total groups needed
            if valid:
                return total_groups

        # This should never happen given the constraints, but return 0 as fallback
        return 0

class Solution:
    def minSum(self, nums1: List[int], nums2: List[int]) -> int:
        # Calculate sum and count of zeros for nums1
        sum1 = sum(nums1)
        zeros1 = nums1.count(0)

        # Calculate sum and count of zeros for nums2
        sum2 = sum(nums2)
        zeros2 = nums2.count(0)

        # Calculate minimum possible sums (replacing zeros with 1s)
        min_sum1 = sum1 + zeros1
        min_sum2 = sum2 + zeros2

        # Case 1: Neither array has zeros
        if zeros1 == 0 and zeros2 == 0:
            if sum1 == sum2:
                return sum1
            else:
                return -1

        # Case 2: Only nums1 has zeros
        if zeros1 == 0 and zeros2 > 0:
            # nums1 sum is fixed, nums2 can only increase
            if sum1 >= min_sum2:
                return sum1
            else:
                return -1

        # Case 3: Only nums2 has zeros
        if zeros1 > 0 and zeros2 == 0:
            # nums2 sum is fixed, nums1 can only increase
            if sum2 >= min_sum1:
                return sum2
            else:
                return -1

        # Case 4: Both arrays have zeros
        # Both can adjust upward, so we take the maximum of their minimum sums
        return max(min_sum1, min_sum2)

class Solution:
    def minChanges(self, s: str) -> int:
        changes = 0
        # Iterate through the string in steps of 2 to form pairs
        for i in range(0, len(s), 2):
            # Check if the two characters in the current pair are different
