                changes += 1
        return changes

class Solution:
    def minimumSum(self, nums: List[int]) -> int:
        n = len(nums)
        if n < 3:
            return -1

        # Precompute left minimums
        left_min = [None] * n
        for j in range(1, n):
            for i in range(j):
                if nums[i] < nums[j]:
                    if left_min[j] is None or nums[i] < left_min[j]:
                        left_min[j] = nums[i]

        # Precompute right minimums
        right_min = [None] * n
        for j in range(n-2, -1, -1):
            for k in range(j+1, n):
                if nums[k] < nums[j]:
                    if right_min[j] is None or nums[k] < right_min[j]:
                        right_min[j] = nums[k]

        # Find minimum mountain sum
        min_sum = float('inf')
        for j in range(1, n-1):
            if left_min[j] is not None and right_min[j] is not None:
                current_sum = left_min[j] + nums[j] + right_min[j]
                min_sum = min(min_sum, current_sum)

        return min_sum if min_sum != float('inf') else -1

class Solution:
    def findKOr(self, nums: List[int], k: int) -> int:
        # Initialize the result to 0
        result = 0

        # Iterate through each bit position from 0 to 30
        # Since nums[i] < 2^31, we only need to check up to the 30th bit
        for i in range(31):
            # Count how many numbers have the i-th bit set
            count = 0
            for num in nums:
                # Check if the i-th bit is set in num
                if num & (1 << i):
                    count += 1

            # If at least k numbers have this bit set, include it in the result
            if count >= k:
                result |= (1 << i)

        return result

class Solution:
    def maxBalancedSubsequenceSum(self, nums: List[int]) -> int:
        n = len(nums)

        # Transform the array: transformed[i] = nums[i] - i
        transformed = [nums[i] - i for i in range(n)]

        # Coordinate compression
        unique_vals = sorted(set(transformed))
        val_to_idx = {val: idx for idx, val in enumerate(unique_vals)}

        # Segment tree for range maximum query
        class SegTree:
            def __init__(self, size):
                self.size = size
                self.tree = [float('-inf')] * (4 * size)

            def update(self, node, start, end, idx, val):
                if start == end:
                    self.tree[node] = max(self.tree[node], val)
                else:
                    mid = (start + end) // 2
                    if idx <= mid:
                        self.update(2*node, start, mid, idx, val)
                    else:
                        self.update(2*node+1, mid+1, end, idx, val)
                    self.tree[node] = max(self.tree[2*node], self.tree[2*node+1])

            def query(self, node, start, end, l, r):
                if r < start or end < l:
                    return float('-inf')
                if l <= start and end <= r:
                    return self.tree[node]
                mid = (start + end) // 2
                return max(self.query(2*node, start, mid, l, r),
                          self.query(2*node+1, mid+1, end, l, r))

            def update_point(self, idx, val):
                self.update(1, 0, self.size - 1, idx, val)

            def query_range(self, l, r):
                if l > r:
                    return float('-inf')
                return self.query(1, 0, self.size - 1, l, r)

        # Initialize segment tree
        seg_tree = SegTree(len(unique_vals))

        # DP approach
        max_sum = float('-inf')

        for i in range(n):
            # Get compressed index
            compressed_idx = val_to_idx[transformed[i]]

            # Query maximum dp value for all j where transformed[j] <= transformed[i]
            prev_max = seg_tree.query_range(0, compressed_idx)

            # Calculate dp[i]
            if prev_max == float('-inf'):
                dp_i = nums[i]
            else:
                dp_i = max(nums[i], prev_max + nums[i])

            # Update the answer
            max_sum = max(max_sum, dp_i)

            # Update segment tree with current dp value
            seg_tree.update_point(compressed_idx, dp_i)

        return max_sum

class Solution:
    def findChampion(self, grid: List[List[int]]) -> int:
        n = len(grid)
        max_wins = -1
        champion = -1

        # Count wins for each team
        for i in range(n):
            wins = sum(grid[i])  # Count 1s in row i
            if wins > max_wins:
                max_wins = wins
                champion = i

        return champion

class Solution:
    def minOperations(self, nums1: List[int], nums2: List[int]) -> int:
        n = len(nums1)

        # Helper function to calculate minimum swaps for a given scenario
        def count_swaps(target1, target2, arr1, arr2):
            swaps = 0
            for i in range(n - 1):
                # If either element already exceeds its target, it's impossible
                if arr1[i] > target1 or arr2[i] > target2:
                    # Check if swapping helps
                    if arr2[i] > target1 or arr1[i] > target2:
                        return -1
                    swaps += 1
            return swaps

        # Get the last elements
        last1, last2 = nums1[n-1], nums2[n-1]

        # Scenario 1: Don't swap the last elements
        swaps1 = count_swaps(last1, last2, nums1, nums2)

        # Scenario 2: Swap the last elements
        swaps2 = count_swaps(last2, last1, nums1, nums2)
        if swaps2 != -1:
            swaps2 += 1  # Add one for swapping the last elements

        # Return the result
        if swaps1 == -1 and swaps2 == -1:
            return -1
        elif swaps1 == -1:
            return swaps2
        elif swaps2 == -1:
            return swaps1
        else:
            return min(swaps1, swaps2)

class Solution:
    def maximumStrongPairXor(self, nums: List[int]) -> int:
        max_xor = 0
        n = len(nums)

        # Check all pairs including same elements
        for i in range(n):
            for j in range(n):
                x, y = nums[i], nums[j]
                # Check if it's a strong pair
                if abs(x - y) <= min(x, y):
                    # Update maximum XOR if needed
                    max_xor = max(max_xor, x ^ y)

        return max_xor

