from collections import Counter

class Solution:
    def maxFrequencyScore(self, nums: List[int], k: int) -> int:
        # Handle special case where no operations are allowed
        if k == 0:
            freq = Counter(nums)
            return max(freq.values())

        # Proceed with normal logic for k > 0
        nums.sort()
        n = len(nums)
        prefix_sum = [0] * (n + 1)
        for i in range(n):
            prefix_sum[i + 1] = prefix_sum[i] + nums[i]

        def get_cost(left, right):
            mid = (left + right) // 2
            left_sum = prefix_sum[mid + 1] - prefix_sum[left]
            right_sum = prefix_sum[right + 1] - prefix_sum[mid + 1]
            count_left = mid - left
            count_right = right - mid
            return (right_sum - left_sum - (count_right - count_left) * nums[mid])

        max_freq = 1
        left = 0

        for right in range(n):
            while left < right and get_cost(left, right) > k:
                left += 1
            max_freq = max(max_freq, right - left + 1)

        return max_freq

class Solution:
    def distributeCandies(self, n: int, limit: int) -> int:
        # If total candies exceed what 3 children can take, it's impossible
        if n > 3 * limit:
            return 0

        count = 0
        # Iterate through all possible candy counts for the first child
        for i in range(min(n, limit) + 1):
            # Remaining candies after giving 'i' candies to the first child
            remaining = n - i

            # If remaining candies are more than what 2 children can take, skip
            if remaining > 2 * limit:
                continue

            # Iterate through all possible candy counts for the second child
            for j in range(min(remaining, limit) + 1):
                # The third child gets the rest of the candies
                k = remaining - j

                # Check if the third child's candy count is within limit
                if 0 <= k <= limit:
                    count += 1

        return count

class Solution:
    def findMinimumOperations(self, s1: str, s2: str, s3: str) -> int:
        # Check if the first characters are the same
        if not (s1[0] == s2[0] == s3[0]):
            return -1

        # Find the length of the common prefix
        min_len = min(len(s1), len(s2), len(s3))
        common_prefix_len = 0

        for i in range(min_len):
            if s1[i] == s2[i] == s3[i]:
                common_prefix_len += 1
            else:
                break

        # If there's no common prefix, it's impossible
        if common_prefix_len == 0:
            return -1

        # Calculate the minimum operations needed
        operations = (len(s1) - common_prefix_len) + (len(s2) - common_prefix_len) + (len(s3) - common_prefix_len)

        return operations

class Solution:
    def beautifulSubstrings(self, s: str, k: int) -> int:
        # Precompute valid lengths: we want n^2 % k == 0 where n = vowels = consonants
        # So total length = 2 * n, and we want to find valid values of 2 * n
        valid_lengths = set()
        for n in range(1, len(s) // 2 + 1):
            if (n * n) % k == 0:
                valid_lengths.add(2 * n)

        # Build prefix sums: diff[i] = (number of vowels - number of consonants) in s[0:i]
        # Also include diff[0] = 0 for empty prefix
        diff = [0]
        for char in s:
            if char in 'aeiou':
                diff.append(diff[-1] + 1)
            else:
                diff.append(diff[-1] - 1)

        # Group indices by their diff values
        from collections import defaultdict
        index_map = defaultdict(list)
        for i, d in enumerate(diff):
            index_map[d].append(i)

        count = 0
        # For each group of indices with the same diff value
        for indices in index_map.values():
            # Check all pairs (i,j) where i < j
            for idx in range(len(indices)):
                for jdx in range(idx + 1, len(indices)):
                    i, j = indices[idx], indices[jdx]
                    length = j - i  # Length of substring s[i:j]
                    if length in valid_lengths:
                        count += 1

        return count

class Solution:
    def numberOfGoodPartitions(self, nums: List[int]) -> int:
        MOD = 10**9 + 7

        # Step 1: Record first and last occurrences
        first = {}
        last = {}
        for i, num in enumerate(nums):
            if num not in first:
                first[num] = i
            last[num] = i

        # Create intervals
        intervals = []
        for num in first:
            intervals.append((first[num], last[num]))

        # Step 2: Sort and merge intervals
        intervals.sort()
        merged = []
        for start, end in intervals:
            if not merged or merged[-1][1] < start:
                merged.append([start, end])
            else:
                merged[-1][1] = max(merged[-1][1], end)

        # Step 3: Count partitions
        k = len(merged)
        # Step 4: Modular exponentiation
        return pow(2, k - 1, MOD)

