class Solution:
    def countCompleteSubstrings(self, word: str, k: int) -> int:
        # Helper function to split word into valid segments
        def get_segments(s):
            segments = []
            start = 0
            for i in range(len(s) - 1):
                if abs(ord(s[i]) - ord(s[i+1])) > 2:
                    segments.append(s[start:i+1])
                    start = i + 1
            segments.append(s[start:])
            return segments

        # Helper function to count valid substrings in a segment
        def count_in_segment(seg):
            count = 0
            n = len(seg)
            # Try all possible numbers of unique characters (1 to 26)
            for x in range(1, 27):
                length = x * k
                if length > n:
                    break
                # Sliding window of fixed size `length`
                freq = {}
                # Initialize the first window
                for i in range(length):
                    c = seg[i]
                    freq[c] = freq.get(c, 0) + 1
                # Check initial window
                if all(v == k for v in freq.values()):
                    count += 1
                # Slide the window
                for i in range(length, n):
                    # Add new character
                    incoming = seg[i]
                    freq[incoming] = freq.get(incoming, 0) + 1
                    # Remove outgoing character
                    outgoing = seg[i - length]
                    freq[outgoing] -= 1
                    if freq[outgoing] == 0:
                        del freq[outgoing]
                    # Check current window
                    if all(v == k for v in freq.values()):
                        count += 1
            return count

        segments = get_segments(word)
        total = 0
        for seg in segments:
            total += count_in_segment(seg)
        return total

class Solution:
    def numberOfSequence(self, n: int, sick: List[int]) -> int:
        MOD = 10**9 + 7

        # Precompute factorials and their modular inverses
        max_n = n
        fact = [1] * (max_n + 1)
        for i in range(1, max_n + 1):
            fact[i] = (fact[i-1] * i) % MOD

        def mod_inverse(x):
            return pow(x, MOD - 2, MOD)

        inv_fact = [1] * (max_n + 1)
        inv_fact[max_n] = mod_inverse(fact[max_n])
        for i in range(max_n - 1, -1, -1):
            inv_fact[i] = (inv_fact[i+1] * (i+1)) % MOD

        def comb(n, k):
            if k > n or k < 0:
                return 0
            return (fact[n] * inv_fact[k] % MOD) * inv_fact[n-k] % MOD

        # Find all uninfected segments
        segments = []

        # Prefix segment (before first sick child)
        if sick[0] > 0:
            segments.append((sick[0], True))  # (length, is_edge)

        # Middle segments (between sick children)
        for i in range(len(sick) - 1):
            length = sick[i+1] - sick[i] - 1
            if length > 0:
                segments.append((length, False))  # not at edge

        # Suffix segment (after last sick child)
        if sick[-1] < n - 1:
            segments.append((n - 1 - sick[-1], True))  # (length, is_edge)

        # Calculate the contribution of each segment
        total_ways = 1
        total_uninfected = 0

        for length, is_edge in segments:
            total_uninfected += length
            if not is_edge:
                # Middle segment: 2^(length-1) ways
                ways = pow(2, length - 1, MOD)
                total_ways = (total_ways * ways) % MOD
            # Edge segments contribute 1 way each, so we multiply by 1 (do nothing)

        # Calculate multinomial coefficient for interleaving
        if total_uninfected == 0:
            return 1

        result = fact[total_uninfected]
        for length, _ in segments:
            result = (result * inv_fact[length]) % MOD

        result = (result * total_ways) % MOD

        return result

class Solution:
    def findMissingAndRepeatedValues(self, grid: List[List[int]]) -> List[int]:
        n = len(grid)
        max_num = n * n

        # Boolean array to track which numbers we've seen
        seen = [False] * (max_num + 1)

        repeated = -1
        missing = -1

        # First pass: Find the repeated number
        for i in range(n):
            for j in range(n):
                num = grid[i][j]
                if seen[num]:
                    repeated = num
                else:
                    seen[num] = True

        # Second pass: Find the missing number
        for i in range(1, max_num + 1):
            if not seen[i]:
                missing = i
                break

        return [repeated, missing]

class Solution:
    def minimumCost(self, nums: List[int]) -> int:
        # Sort the array to find median
        nums.sort()
        n = len(nums)

        # Find median
        median = nums[n // 2]

        # Helper function to check if a number is palindromic
        def is_palindrome(x):
            s = str(x)
            return s == s[::-1]

        # Find the largest palindromic number <= median
        def find_floor_palindrome(x):
            while x >= 0:
                if is_palindrome(x):
                    return x
                x -= 1
            return 0

        # Find the smallest palindromic number >= median
        def find_ceil_palindrome(x):
            while x < 10**10:  # Upper bound check
                if is_palindrome(x):
                    return x
                x += 1
            return x

        # Get candidate palindromes
        floor_pal = find_floor_palindrome(median)
        ceil_pal = find_ceil_palindrome(median)

        # Calculate cost for a target value
        def calculate_cost(target):
            return sum(abs(num - target) for num in nums)

        # Return minimum cost between the two candidates
        return min(calculate_cost(floor_pal), calculate_cost(ceil_pal))

class Solution:
    def removeAlmostEqualCharacters(self, word: str) -> int:
        operations = 0
        i = 0
        n = len(word)

        while i < n - 1:
            # Check if current and next characters are almost-equal
            if abs(ord(word[i]) - ord(word[i + 1])) <= 1:
                operations += 1
                # Skip the next character as we consider it modified
                i += 2
            else:
                i += 1

        return operations

class Solution:
    def getGoodIndices(self, variables: List[List[int]], target: int) -> List[int]:
        result = []

        # Iterate through each variable set with its index
        for i, (a, b, c, m) in enumerate(variables):
            # First stage: compute a^b % 10
            step1 = pow(a, b, 10)

            # Second stage: compute (result of first stage)^c % m
            final_result = pow(step1, c, m)

            # Check if final result matches target
            if final_result == target:
                result.append(i)

        return result

class Solution:
    def minimumCost(self, source: str, target: str, original: List[str], changed: List[str], cost: List[int]) -> int:
        import math

        # Number of lowercase letters
        NUM_LETTERS = 26

        # Initialize cost matrix with infinity
        cost_matrix = [[math.inf] * NUM_LETTERS for _ in range(NUM_LETTERS)]

        # Set diagonal to 0 (no cost to change a character to itself)
        for i in range(NUM_LETTERS):
            cost_matrix[i][i] = 0

        # Populate direct transformation costs
        for i in range(len(original)):
            orig_idx = ord(original[i]) - ord('a')
            chng_idx = ord(changed[i]) - ord('a')
            cost_matrix[orig_idx][chng_idx] = min(cost_matrix[orig_idx][chng_idx], cost[i])

        # Floyd-Warshall Algorithm to compute all-pairs shortest paths
        for k in range(NUM_LETTERS):
            for i in range(NUM_LETTERS):
                for j in range(NUM_LETTERS):
                    if cost_matrix[i][k] + cost_matrix[k][j] < cost_matrix[i][j]:
                        cost_matrix[i][j] = cost_matrix[i][k] + cost_matrix[k][j]

        # Calculate total minimum cost to convert source to target
        total_cost = 0
        for i in range(len(source)):
            if source[i] == target[i]:
                continue
            orig_idx = ord(source[i]) - ord('a')
            targ_idx = ord(target[i]) - ord('a')

            # If no path exists, return -1
            if cost_matrix[orig_idx][targ_idx] == math.inf:
                return -1

            total_cost += cost_matrix[orig_idx][targ_idx]

        return total_cost

class Solution:
    def missingInteger(self, nums: List[int]) -> int:
        # Step 1: Find the longest sequential prefix and calculate its sum
        prefix_sum = nums[0]
        for i in range(1, len(nums)):
            if nums[i] == nums[i-1] + 1:
                prefix_sum += nums[i]
            else:
                break

        # Step 2: Create a set for O(1) lookup
        num_set = set(nums)

        # Step 3: Find the smallest missing integer >= prefix_sum
        candidate = prefix_sum
        while candidate in num_set:
            candidate += 1

        return candidate

class Solution:
    def maxFrequencyElements(self, nums: List[int]) -> int:
        # Step 1: Count frequencies of each element
        freq_map = {}
        for num in nums:
            freq_map[num] = freq_map.get(num, 0) + 1

        # Step 2: Find the maximum frequency
        max_freq = max(freq_map.values())

        # Step 3: Sum up the frequencies of elements with maximum frequency
        total_count = 0
        for freq in freq_map.values():
            if freq == max_freq:
                total_count += freq

        return total_count

class Solution:
    def beautifulIndices(self, s: str, a: str, b: str, k: int) -> List[int]:
        # Step 1: Find all occurrences of pattern a and b
        a_indices = []
        b_indices = []

        # Find all starting positions of pattern 'a'
        for i in range(len(s) - len(a) + 1):
            if s[i:i+len(a)] == a:
                a_indices.append(i)

        # Find all starting positions of pattern 'b'
        for j in range(len(s) - len(b) + 1):
            if s[j:j+len(b)] == b:
                b_indices.append(j)

        # Step 2: Use two pointers to check beautiful condition
        result = []
        j = 0  # Pointer for b_indices

        # Step 3: For each index in a_indices, check if there's a valid index in b_indices
        for i in a_indices:
            # Move j to the first position where b_indices[j] >= i - k
            while j < len(b_indices) and b_indices[j] < i - k:
                j += 1

            # Check if current j satisfies the condition
            if j < len(b_indices) and b_indices[j] <= i + k:
                result.append(i)

        return result

class Solution:
    def hasTrailingZeros(self, nums: List[int]) -> bool:
        # Count the number of even elements
        even_count = 0
        for num in nums:
            if num % 2 == 0:
                even_count += 1
                # If we find at least two even numbers, we can return True
                if even_count >= 2:
                    return True
        # If we don't find at least two even numbers, return False
        return False

class Solution:
    def minOperations(self, nums: List[int], k: int) -> int:
        # Step 1: Calculate the XOR of all elements in the array
        current_xor = 0
        for num in nums:
            current_xor ^= num

        # Step 2: Find the difference between current XOR and target k
        diff = current_xor ^ k

        # Step 3: Count the number of 1-bits in the difference
        # This count represents the minimum number of bit flips needed
        return bin(diff).count('1')

class Solution:
    def areaOfMaxDiagonal(self, dimensions: List[List[int]]) -> int:
        max_diagonal_squared = 0
        max_area = 0

        for length, width in dimensions:
            diagonal_squared = length * length + width * width
            area = length * width

            if diagonal_squared > max_diagonal_squared:
                max_diagonal_squared = diagonal_squared
                max_area = area
            elif diagonal_squared == max_diagonal_squared:
                max_area = max(max_area, area)

        return max_area

class Solution:
    def incremovableSubarrayCount(self, nums: List[int]) -> int:
        n = len(nums)
        count = 0

        # Helper function to check if an array is strictly increasing
        def is_strictly_increasing(arr):
            for i in range(len(arr) - 1):
                if arr[i] >= arr[i + 1]:
                    return False
            return True

        # Iterate over all possible subarrays
        for i in range(n):
            for j in range(i, n):
                # Create the remaining array after removing subarray from index i to j
                remaining = nums[:i] + nums[j+1:]

                # Check if the remaining array is strictly increasing
                if is_strictly_increasing(remaining):
                    count += 1

        return count

class Solution:
    def maximumLength(self, s: str) -> int:
        # Dictionary to store counts: counts[char][length] = occurrences
        counts = {}
        n = len(s)
        i = 0

        # Step 1: Identify consecutive character runs
        while i < n:
            char = s[i]
            start = i
            # Extend the run as long as characters are the same
            while i < n and s[i] == char:
                i += 1
            run_length = i - start

            # Step 2: Count special substrings for this run
            if char not in counts:
                counts[char] = {}

            # For each possible substring length in the run
            for k in range(1, run_length + 1):
                # Number of substrings of length k in a run of length run_length
                substring_count = run_length - k + 1
                if k not in counts[char]:
                    counts[char][k] = 0
                counts[char][k] += substring_count

        # Step 3 & 4: Find the maximum length with count >= 3
        max_length = -1
        for char in counts:
            for length in counts[char]:
                if counts[char][length] >= 3:
                    max_length = max(max_length, length)

        return max_length

class Solution:
    def countMatchingSubarrays(self, nums: List[int], pattern: List[int]) -> int:
        n = len(nums)
        m = len(pattern)
        count = 0

        # Iterate through all possible starting positions
        for i in range(n - m):
            match = True

            # Check each pattern condition for the current subarray
            for k in range(m):
                if pattern[k] == 1:
                    if nums[i + k + 1] <= nums[i + k]:
                        match = False
                        break
                elif pattern[k] == 0:
                    if nums[i + k + 1] != nums[i + k]:
                        match = False
                        break
                else:  # pattern[k] == -1
                    if nums[i + k + 1] >= nums[i + k]:
                        match = False
                        break

            # If all pattern conditions are satisfied, increment count
            if match:
                count += 1

        return count

class Solution:
    def lastNonEmptyString(self, s: str) -> str:
        # Step 1: Calculate frequency of each character and track last positions
        freq = {}
        last_pos = {}

        for i, char in enumerate(s):
            freq[char] = freq.get(char, 0) + 1
            last_pos[char] = i

        # Step 2: Find the maximum frequency
        max_freq = max(freq.values())

        # Step 3: Identify characters with maximum frequency
        max_freq_chars = set(char for char, f in freq.items() if f == max_freq)

        # Step 4: Collect the last occurrences of max frequency characters in order
        result = []
        for i, char in enumerate(s):
            # If character has max frequency and this is its last occurrence
            if char in max_freq_chars and last_pos[char] == i:
                result.append(char)

        return ''.join(result)

class Solution:
    def countPrefixSuffixPairs(self, words: List[str]) -> int:
        def isPrefixAndSuffix(str1, str2):
            # Check if str1 is both a prefix and suffix of str2
            if len(str1) > len(str2):
                return False
            return str2.startswith(str1) and str2.endswith(str1)

        count = 0
        n = len(words)

        # Check all pairs (i, j) where i < j
        for i in range(n - 1):
            for j in range(i + 1, n):
                if isPrefixAndSuffix(words[i], words[j]):
                    count += 1

        return count

