class Solution:
    def maxPalindromesAfterOperations(self, words: List[str]) -> int:
        # Count frequency of all characters across all words
        char_count = {}
        for word in words:
            for c in word:
                char_count[c] = char_count.get(c, 0) + 1

        # Calculate total number of character pairs available
        total_pairs = 0
        for count in char_count.values():
            total_pairs += count // 2

        # Get word lengths and sort them to apply greedy strategy
        word_lengths = [len(word) for word in words]
        word_lengths.sort()

        # Try to form palindromes starting from shortest words
        palindromes_formed = 0
        for length in word_lengths:
            # A palindrome of length 'length' needs 'length // 2' pairs
            required_pairs = length // 2
            if total_pairs >= required_pairs:
                total_pairs -= required_pairs
                palindromes_formed += 1
            else:
                # Not enough pairs to form this palindrome
                break

        return palindromes_formed

class Solution:
    def isPossibleToSplit(self, nums: List[int]) -> bool:
