        freq = {}
        for num in nums:
            freq[num] = freq.get(num, 0) + 1

        # Check if any element appears more than 2 times
        for count in freq.values():
            if count > 2:
                return False

        return True

class Solution:
    def longestCommonPrefix(self, arr1: List[int], arr2: List[int]) -> int:
        # Define a Trie node as a dictionary
        trie = {}

        # Function to insert a string into the Trie
        def insert(s):
            node = trie
            for char in s:
                if char not in node:
                    node[char] = {}
                node = node[char]

        # Function to search for the longest prefix match in the Trie
        def search(s):
            node = trie
            length = 0
