import sys

def bfs_distance(grid, start, targets, H, W):
    """Compute shortest distances from start to all target positions"""
    distances = {}
    queue = deque([(start[0], start[1], 0)])
    visited = set()
    visited.add((start[0], start[1]))

    target_set = set(targets)
    found = 0

    while queue and found < len(targets):
        r, c, dist = queue.popleft()

        if (r, c) in target_set:
            distances[(r, c)] = dist
            found += 1

        # Explore neighbors
        for dr, dc in [(0, 1), (0, -1), (1, 0), (-1, 0)]:
            nr, nc = r + dr, c + dc
            if 0 <= nr < H and 0 <= nc < W and grid[nr][nc] != '#' and (nr, nc) not in visited:
                visited.add((nr, nc))
                queue.append((nr, nc, dist + 1))

    return distances

def main():
    # Read input
    line = input().split()
    H, W, T = int(line[0]), int(line[1]), int(line[2])

    grid = []
    for _ in range(H):
        grid.append(input().strip())

    # Find positions
    start_pos = None
    goal_pos = None
    candy_positions = []

    for i in range(H):
        for j in range(W):
            if grid[i][j] == 'S':
                start_pos = (i, j)
            elif grid[i][j] == 'G':
                goal_pos = (i, j)
            elif grid[i][j] == 'o':
                candy_positions.append((i, j))

    # Check if path exists within T moves
    simple_distances = bfs_distance(grid, start_pos, [goal_pos], H, W)
    if goal_pos not in simple_distances or simple_distances[goal_pos] > T:
        print(-1)
        return

    num_candies = len(candy_positions)
    if num_candies == 0:
        print(0)
        return

    # Precompute all pairwise distances
    # Include start, goal, and all candy positions
    all_positions = [start_pos] + candy_positions + [goal_pos]
    n_positions = len(all_positions)

    # Distance matrix: dist[i][j] = shortest distance from position i to position j
    dist = [[float('inf')] * n_positions for _ in range(n_positions)]

    for i in range(n_positions):
        distances_from_i = bfs_distance(grid, all_positions[i], all_positions, H, W)
        for j in range(n_positions):
            if all_positions[j] in distances_from_i:
                dist[i][j] = distances_from_i[all_positions[j]]

    # Bitmask DP
    # dp[mask][last] = minimum moves to visit candies in mask, ending at candy 'last'
    INF = float('inf')
    dp = [[INF] * num_candies for _ in range(1 << num_candies)]

    # Initialize: start from S to each candy
    for i in range(num_candies):
        dp[1 << i][i] = dist[0][i + 1]  # 0 is start_pos, i+1 because candies start at index 1

    # Fill DP table
    for mask in range(1 << num_candies):
        for last in range(num_candies):
            if not (mask & (1 << last)):
                continue
            if dp[mask][last] == INF:
                continue

            # Try extending to unvisited candies
            for next_candy in range(num_candies):
                if mask & (1 << next_candy):
                    continue
                new_mask = mask | (1 << next_candy)
                new_cost = dp[mask][last] + dist[last + 1][next_candy + 1]
                if new_cost < dp[new_mask][next_candy]:
                    dp[new_mask][next_candy] = new_cost

    # Find maximum candies that can be collected within T moves
    max_candies = 0

    for mask in range(1 << num_candies):
        candy_count = bin(mask).count('1')
        # From any final candy position to goal
        for last in range(num_candies):
            if not (mask & (1 << last)):
                continue
            total_moves = dp[mask][last] + dist[last + 1][num_candies + 1]  # num_candies + 1 is goal index
            if total_moves <= T:
                max_candies = max(max_candies, candy_count)

    print(max_candies)

