def compare_people(person1, person2):
    # person1 = (id1, a1, b1)
    # person2 = (id2, a2, b2)
    id1, a1, b1 = person1
    id2, a2, b2 = person2

    # Cross multiply to compare fractions
    # Compare a1/(a1+b1) vs a2/(a2+b2)
    # This is equivalent to comparing a1*(a2+b2) vs a2*(a1+b1)
    left = a1 * (a2 + b2)
    right = a2 * (a1 + b1)

    if left > right:
        return -1  # person1 should come first (higher success rate)
    elif left < right:
        return 1   # person2 should come first (higher success rate)
    else:
        # Success rates are equal, break tie by person ID
        if id1 < id2:
            return -1  # person1 should come first (lower ID)
        elif id1 > id2:
            return 1   # person2 should come first (lower ID)
        else:
            return 0   # same person

