    idx_M = []
    idx_E = []
    idx_X = []

    for i in range(N):
        if S[i] == 'M':
            idx_M.append(i)
        elif S[i] == 'E':
            idx_E.append(i)
        else:  # S[i] == 'X'
            idx_X.append(i)

    # Precompute mex values
    mex_table = {}
    for a in range(3):
        for b in range(3):
            for c in range(3):
                key = tuple(sorted([a, b, c]))
                if key not in mex_table:
                    mex_table[key] = mex([a, b, c])

    result = 0

    # For each E position
    for j in idx_E:
        e_val = A[j]

        # Count values at M positions before j using binary search
        m_counts = [0, 0, 0]
        # Find how many M indices are before j
        m_pos = bisect.bisect_left(idx_M, j)
        for i in range(m_pos):
            m_counts[A[idx_M[i]]] += 1

        # Count values at X positions after j using binary search
        x_counts = [0, 0, 0]
        # Find how many X indices are after j
        x_pos = bisect.bisect_right(idx_X, j)
        for i in range(x_pos, len(idx_X)):
            x_counts[A[idx_X[i]]] += 1

        # Calculate contribution
        for m_val in range(3):
            for x_val in range(3):
                count = m_counts[m_val] * x_counts[x_val]
                if count > 0:
                    key = tuple(sorted([m_val, e_val, x_val]))
                    result += mex_table[key] * count

    print(result)

