    x1, y1, z1 = cuboid1['x'], cuboid1['y'], cuboid1['z']
    x2, y2, z2 = cuboid2['x'], cuboid2['y'], cuboid2['z']

    # Check X-face adjacency
    if x1[1] == x2[0] or x1[0] == x2[1]:
        if has_positive_overlap_2d(y1, z1, y2, z2):
            return True

    # Check Y-face adjacency
    if y1[1] == y2[0] or y1[0] == y2[1]:
        if has_positive_overlap_2d(x1, z1, x2, z2):
            return True

    # Check Z-face adjacency
    if z1[1] == z2[0] or z1[0] == z2[1]:
        if has_positive_overlap_2d(x1, y1, x2, y2):
            return True

    return False

