import sys
from itertools import product

def parse_polyomino(lines):
    """Parse a 4x4 grid into a set of coordinates where '#' appears"""
    coords = set()
    for r in range(4):
        for c in range(4):
            if lines[r][c] == '#':
                coords.add((r, c))
    return coords

def normalize(coords):
    """Normalize coordinates to start from (0,0)"""
    if not coords:  # Handle empty coordinates safely
        return frozenset()
    try:
        min_r = min(r for r, c in coords)
        min_c = min(c for r, c in coords)
        return frozenset((r - min_r, c - min_c) for r, c in coords)
    except ValueError:
        return frozenset()  # Fallback for unexpected empty sequences

def rotate_90(coords):
    """Rotate coordinates 90 degrees clockwise"""
    # (r, c) -> (c, -r)
    rotated_list = [(c, -r) for r, c in coords]
    return normalize(rotated_list)

def get_rotations(coords):
    """Get all 4 rotations of a polyomino"""
    if not coords:
        return [frozenset()]
    rotations = []
    current = coords
    for _ in range(4):
        if current not in rotations:  # Avoid adding duplicate rotations
            rotations.append(current)
        current = rotate_90(current)
    return rotations

def get_valid_placements(polyomino_coords):
    """Get all valid placements (rotation, dr, dc) on a 4x4 grid"""
    placements = []
    rotations = get_rotations(polyomino_coords)

    for i, rotation in enumerate(rotations):
        # Try all possible offsets
        for dr in range(4):
            for dc in range(4):
                # Check if this placement fits on the grid
                valid = True
                new_cells = set()
                for r, c in rotation:
                    nr, nc = r + dr, c + dc
                    if not (0 <= nr < 4 and 0 <= nc < 4):
                        valid = False
                        break
                    new_cells.add((nr, nc))
                if valid:
                    placements.append((i, dr, dc, frozenset(new_cells)))
    return placements

def can_fill_grid(polyominoes):
    """Check if three polyominoes can fill a 4x4 grid"""
    # Get all valid placements for each polyomino
    all_placements = []
    for poly in polyominoes:
        placements = get_valid_placements(poly)
        all_placements.append(placements)

    # Try all combinations
    def backtrack(poly_idx, occupied):
        if poly_idx == 3:
            # Check if all cells are filled
            return len(occupied) == 16

        # Try each placement for current polyomino
        for rotation_idx, dr, dc, new_cells in all_placements[poly_idx]:
            # Check if placement conflicts with already occupied cells
            if not (new_cells & occupied):  # No intersection
                # Place polyomino
                occupied_new = occupied | new_cells
                if backtrack(poly_idx + 1, occupied_new):
                    return True

        return False

    return backtrack(0, set())

