def can_transform_by_insertion(short_str, long_str):
    # Check if long_str can be formed by inserting one character into short_str
    if len(long_str) != len(short_str) + 1:
        return False

    i, j = 0, 0  # i for short_str, j for long_str
    diff_count = 0

    while i < len(short_str) and j < len(long_str):
        if short_str[i] == long_str[j]:
            i += 1
            j += 1
        else:
            # Found a difference, skip this character in long_str
            diff_count += 1
            if diff_count > 1:
                return False
            j += 1

    return True

def can_transform_by_deletion(long_str, short_str):
    # Check if short_str can be formed by deleting one character from long_str
    # This is equivalent to inserting one character into short_str to get long_str
    return can_transform_by_insertion(short_str, long_str)

def can_transform_by_replacement(str1, str2):
    # Check if str1 can be transformed to str2 by changing exactly one character
    if len(str1) != len(str2):
        return False

    diff_count = 0
    for i in range(len(str1)):
        if str1[i] != str2[i]:
            diff_count += 1
            if diff_count > 1:
                return False

    return diff_count == 1

def is_valid_original(original, received):
    len_diff = len(received) - len(original)

    if len_diff == 0:
        # Same length: either identical or one replacement
        if original == received:
            return True
        return can_transform_by_replacement(original, received)

    elif len_diff == 1:
        # received is one character longer: original -> received by insertion
        return can_transform_by_insertion(original, received)

    elif len_diff == -1:
        # received is one character shorter: original -> received by deletion
        return can_transform_by_deletion(original, received)

    else:
        # Length difference more than 1: impossible
        return False

