from collections import Counter
import math

def is_perfect_square(n):
    if n < 0:
        return False
    root = int(math.isqrt(n))
    return root * root == n

def main():
    n = int(input())
    s = input().strip()

    def backtrack(counter, path, target_len):
        if len(path) == target_len:
            res = ''.join(path)
            if res[0] != '0':
                yield int(res)
            return
        for digit in counter:
            if counter[digit] > 0:
                counter[digit] -= 1
                path.append(digit)
                yield from backtrack(counter, path, target_len)
                path.pop()
                counter[digit] += 1

    digit_count = Counter(s)
    square_numbers = set()

    for number in backtrack(digit_count, [], n):
        if is_perfect_square(number):
            square_numbers.add(number)

    print(len(square_numbers))

