from collections import deque

def solve():
    N, M = map(int, input().split())
    S = input().strip()
    T = input().strip()

    chars = list(S)
    visited = [False] * (N - M + 1)
    queue = deque()

    # Initialize all valid starting positions matching T
    for i in range(N - M + 1):
        match = True
        for j in range(M):
            if chars[i + j] != T[j]:
                match = False
                break
        if match:
            queue.append(i)

    changed = True
    while changed:
        changed = False
        changed_ranges = []

        # Process all current candidates
        curr_len = len(queue)
        for _ in range(curr_len):
            i = queue.popleft()
            if visited[i]:
                continue
            visited[i] = True
            changed = True

            # Apply transformation
            for j in range(M):
                chars[i + j] = '#'

            # Record affected area
            changed_ranges.append((max(0, i - M + 1), min(N - M, i + M - 1)))

        # Scan limited windows for new valid segments
        new_positions = set()
        for start, end in changed_ranges:
            for i in range(start, end + 1):
                if visited[i]:
                    continue
                match = True
                for j in range(M):
                    if chars[i + j] != T[j]:
                        match = False
                        break
                if match:
                    new_positions.add(i)

        queue.extend(new_positions)

    # Final verification
    if all(c == '#' for c in chars):
        print("Yes")
    else:
        print("No")

