from collections import deque
import sys

def main():
    MOD = 998244353

    def modinv(a, mod):
        return pow(a, mod - 2, mod)

    # Read input
    H, W = map(int, input().split())
    grid = []
    for _ in range(H):
        grid.append(list(input().strip()))

    # Find all red cells
    red_cells = []
    for i in range(H):
        for j in range(W):
            if grid[i][j] == '.':
                red_cells.append((i, j))

    if not red_cells:
        # No red cells, but problem guarantees at least one
        return

    # Label connected components using BFS
    component_id = [[-1] * W for _ in range(H)]
    component_count = 0

    def bfs(start_i, start_j, cid):
        queue = deque([(start_i, start_j)])
        component_id[start_i][start_j] = cid
        while queue:
            i, j = queue.popleft()
            for di, dj in [(0, 1), (0, -1), (1, 0), (-1, 0)]:
                ni, nj = i + di, j + dj
                if 0 <= ni < H and 0 <= nj < W and grid[ni][nj] == '#' and component_id[ni][nj] == -1:
                    component_id[ni][nj] = cid
                    queue.append((ni, nj))

    # Label all green components
    for i in range(H):
        for j in range(W):
            if grid[i][j] == '#' and component_id[i][j] == -1:
                bfs(i, j, component_count)
                component_count += 1

    # For each red cell, find adjacent component IDs
    total_change = 0
    n_red = len(red_cells)

    for i, j in red_cells:
        adjacent_components = set()
        for di, dj in [(0, 1), (0, -1), (1, 0), (-1, 0)]:
            ni, nj = i + di, j + dj
            if 0 <= ni < H and 0 <= nj < W and grid[ni][nj] == '#':
                adjacent_components.add(component_id[ni][nj])

        # Calculate change in component count
        num_adjacent = len(adjacent_components)
        if num_adjacent == 0:
            # Creates new component
            change = 1
        elif num_adjacent == 1:
            # Joins to one component, no change
            change = 0
        else:
            # Merges multiple components
            change = -(num_adjacent - 1)

        total_change += change

    # Expected value = original_components + average_change
    # E = component_count + total_change / n_red
    # E = (component_count * n_red + total_change) / n_red

    numerator = (component_count * n_red + total_change) % MOD
    denominator = n_red % MOD

    # Calculate modular inverse of denominator
    result = (numerator * modinv(denominator, MOD)) % MOD

    print(result)

