def can_form_pyramid(A, k):
    if k == 1:
        # For pyramid of size 1, we need at least one element >= 1
        return any(a >= 1 for a in A)

    target_length = 2 * k - 1
    if target_length > len(A):
        return False

    # Create the target pyramid pattern
    target = list(range(1, k + 1)) + list(range(k - 1, 0, -1))

    # Sliding window approach
    min_cost = float('inf')

    # Try all possible windows of size target_length
    for i in range(len(A) - target_length + 1):
        cost = 0
        valid = True

        # Calculate cost for this window
        for j in range(target_length):
            if A[i + j] < target[j]:
                valid = False
                break
            cost += A[i + j] - target[j]

        if valid:
            min_cost = min(min_cost, cost)

    return min_cost != float('inf')

