import sys
from collections import defaultdict, deque

def solve():
    # Step 1: Graph Representation and Input Parsing
    N, M = map(int, input().split())

    # Adjacency list representation
    graph = defaultdict(list)
    edges = []

    for _ in range(M):
        u, v, w = map(int, input().split())
        graph[u].append((v, w))
        edges.append((u, v, w))

    # Step 2: Checking Strong Connectivity
    def is_strongly_connected():
        # First BFS/DFS from vertex 1 in original graph
        visited = set()
        queue = deque([1])
        visited.add(1)

        while queue:
            node = queue.popleft()
            for neighbor, _ in graph[node]:
                if neighbor not in visited:
                    visited.add(neighbor)
                    queue.append(neighbor)

        if len(visited) != N:
            return False

        # Create transpose graph
        transpose_graph = defaultdict(list)
        for u, v, w in edges:
            transpose_graph[v].append((u, w))

        # Second BFS/DFS from vertex 1 in transpose graph
        visited_t = set()
        queue = deque([1])
        visited_t.add(1)

        while queue:
            node = queue.popleft()
            for neighbor, _ in transpose_graph[node]:
                if neighbor not in visited_t:
                    visited_t.add(neighbor)
                    queue.append(neighbor)

        return len(visited_t) == N

    if not is_strongly_connected():
        print("No")
        return

    # Step 3: All-Pairs Shortest Path Computation using Floyd-Warshall
    INF = float('inf')
    dist = [[INF] * (N + 1) for _ in range(N + 1)]

    # Initialize diagonal to 0
    for i in range(1, N + 1):
        dist[i][i] = 0

    # Initialize direct edges
    for u, v, w in edges:
        dist[u][v] = min(dist[u][v], w)

    # Floyd-Warshall algorithm
    for k in range(1, N + 1):
        for i in range(1, N + 1):
            for j in range(1, N + 1):
                if dist[i][k] < INF and dist[k][j] < INF:
                    dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])

    # Step 4: Bitmask Dynamic Programming
    # dp[mask][u] = minimum cost to visit all vertices in mask and end at vertex u
    ALL = (1 << N) - 1
    dp = [[INF] * (N + 1) for _ in range(1 << N)]

    # Initialize: starting from each vertex
    for i in range(1, N + 1):
        dp[1 << (i - 1)][i] = 0

    # Fill DP table
    for mask in range(1 << N):
        for u in range(1, N + 1):
            if not (mask & (1 << (u - 1))):  # u is not in mask
                continue
            if dp[mask][u] == INF:
                continue

            # Try to extend to all other vertices using precomputed shortest paths
            for v in range(1, N + 1):
                if v == u:
                    continue
                new_mask = mask | (1 << (v - 1))
                if dist[u][v] < INF:
                    dp[new_mask][v] = min(dp[new_mask][v], dp[mask][u] + dist[u][v])

    # Find minimum cost to visit all vertices
    result = INF
    for u in range(1, N + 1):
        if dp[ALL][u] < INF:
            result = min(result, dp[ALL][u])

    if result == INF:
        print("No")
    else:
        print(result)

